// Generated by GitHub Copilot
// Para que sirve: Pagina del carrito con cantidades, cupones y resumen de compra.
// Entradas: Props, hooks de contexto y/o estado local segun el archivo.
// Flujo principal: Lee estado, aplica reglas de UI/negocio y renderiza la vista.
// Donde tocar cambios: Ajusta este archivo para modificar su comportamiento principal.
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import ConfirmDialog from '../components/ConfirmDialog';
import { MAX_ITEM_QUANTITY } from '../context/cartConstants';
import { COUPONS, getCouponExpiryInfo } from '../data/coupons';
import useCart from '../context/useCart';
import useLanguage from '../context/useLanguage';
import useDocumentTitle from '../hooks/useDocumentTitle';

/* Maintenance guide:
 * - Quantity changes and remove actions dispatch directly to CartContext reducer.
 * - Coupon flow uses applyCoupon/removeCoupon from context; suggestion chips come from COUPONS.
 * - Keyboard shortcuts are managed in the keydown effect ('/' and Ctrl/Cmd+Enter).
 * - "Guardar para despues" moves item to favorites and removes it from cart in one click.
 */

/**
 * Cart page displaying current cart items with quantity controls and total.
 * Allows removing items and navigating to checkout.
 */
export default function Cart() {
  const { t, formatCurrency, formatDateTime, translateProductText } = useLanguage();
  // WCAG 2.4.2: descriptive page title announced by screen readers on navigation.
  useDocumentTitle(t('cart.title'));
  const navigate = useNavigate();
  const {
    cart,
    dispatch,
    totalItems,
    totalPrice,
    discountAmount,
    finalPrice,
    coupon,
    applyCoupon,
    removeCoupon,
    showToast,
    isFavorite,
    toggleFavorite,
  } = useCart();

  const [couponInput, setCouponInput] = useState('');
  const [couponError, setCouponError] = useState('');
  const [isConfirmClearOpen, setIsConfirmClearOpen] = useState(false);
  const cartHeadingRef = useRef(null);
  const couponInputRef = useRef(null);
  const removeButtonRefs = useRef(new Map());
  const pendingFocusItemIdRef = useRef(null);
  const pendingFocusEmptyStateRef = useRef(false);

  // Quick chips improve conversion by reducing friction when applying discounts.
  const couponSuggestions = useMemo(() => Object.values(COUPONS).slice(0, 4), []);
  const couponExpiryInfo = useMemo(() => {
    const { expiresAt, daysRemaining, isExpiringSoon } = getCouponExpiryInfo(coupon);
    return {
      expiresOn: expiresAt,
      daysRemaining,
      isExpiringToday: daysRemaining === 0,
      isExpiringTomorrow: daysRemaining === 1,
      isExpiringSoon,
    };
  }, [coupon]);

  useEffect(() => {
    /** Keyboard shortcuts: '/' focuses coupon input and Ctrl/Cmd+Enter goes to checkout. */
    const handleKeydown = (event) => {
      const targetTag = event.target?.tagName?.toLowerCase();
      const isTypingField = targetTag === 'input' || targetTag === 'textarea' || event.target?.isContentEditable;

      if (!isTypingField && event.key === '/') {
        event.preventDefault();
        couponInputRef.current?.focus();
      }

      if ((event.ctrlKey || event.metaKey) && event.key === 'Enter' && cart.length > 0) {
        event.preventDefault();
        navigate('/checkout');
      }
    };

    window.addEventListener('keydown', handleKeydown);
    return () => window.removeEventListener('keydown', handleKeydown);
  }, [cart.length, navigate]);

  useEffect(() => {
    const pendingItemId = pendingFocusItemIdRef.current;
    if (pendingItemId != null) {
      const nextRemoveButton = removeButtonRefs.current.get(pendingItemId);
      if (nextRemoveButton) {
        nextRemoveButton.focus();
        pendingFocusItemIdRef.current = null;
        pendingFocusEmptyStateRef.current = false;
      }
      return;
    }

    if (pendingFocusEmptyStateRef.current && cart.length === 0) {
      cartHeadingRef.current?.focus();
      pendingFocusEmptyStateRef.current = false;
    }
  }, [cart]);

  // Generated by GitHub Copilot
  const handleApplyCoupon = useCallback((e) => {
    e.preventDefault();
    if (!couponInput.trim()) {
      setCouponError(t('cart.emptyCoupon'));
      return;
    }
    const ok = applyCoupon(couponInput);
    if (ok) {
      setCouponInput('');
      setCouponError('');
    } else {
      setCouponError(t('cart.invalidCoupon'));
    }
  }, [applyCoupon, couponInput, t]);

  /** Applies one suggested coupon code from quick chips. */
  const handleApplySuggestedCoupon = useCallback((code) => {
    const ok = applyCoupon(code);
    if (!ok) {
      setCouponError(t('cart.invalidCoupon'));
      return;
    }
    setCouponInput('');
    setCouponError('');
  }, [applyCoupon, t]);

  // Generated by GitHub Copilot
  // Defined before the early return so useCallback is unconditional (Rules of Hooks).
  const handleQuantity = useCallback((id, quantity) => {
    dispatch({ type: 'UPDATE_QUANTITY', payload: { id, quantity } });
  }, [dispatch]);

  const handleRemove = useCallback((id) => {
    const currentIds = cart.map((item) => item.id);
    const currentIndex = currentIds.indexOf(id);
    const remainingIds = currentIds.filter((itemId) => itemId !== id);

    if (remainingIds.length > 0) {
      const nextIndex = Math.min(currentIndex, remainingIds.length - 1);
      pendingFocusItemIdRef.current = remainingIds[nextIndex];
      pendingFocusEmptyStateRef.current = false;
    } else {
      pendingFocusItemIdRef.current = null;
      pendingFocusEmptyStateRef.current = true;
    }

    const itemToRemove = cart.find((item) => item.id === id);
    dispatch({ type: 'REMOVE_ITEM', payload: { id } });
    if (itemToRemove) {
      showToast(t('cart.removedFromCart', { name: translateProductText(itemToRemove.name) }), 'info');
    }
  }, [cart, dispatch, showToast, t, translateProductText]);

  const handleClearCart = useCallback(() => {
    dispatch({ type: 'CLEAR_CART' });
    showToast(t('cart.cleared'), 'info');
    setIsConfirmClearOpen(false);
  }, [dispatch, showToast, t]);

  if (cart.length === 0) {
    return (
      <main className="max-w-2xl mx-auto px-4 py-16 text-center">
        <h1 ref={cartHeadingRef} className="text-2xl font-bold text-gray-800 mb-2" tabIndex={-1}>{t('cart.emptyTitle')}</h1>
        <p className="text-gray-500 mb-6">{t('cart.emptyBody')}</p>
        <Link
          to="/"
          className="inline-block bg-indigo-600 hover:bg-indigo-700 text-white font-medium px-6 py-2 rounded-lg transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
        >
          {t('cart.viewProducts')}
        </Link>
      </main>
    );
  }

  return (
    <main className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-gray-900 mb-6">
        {t('cart.title')} ({t('cart.itemCount', { count: totalItems, suffix: totalItems === 1 ? '' : 's' })})
      </h1>

      <p className="sr-only" role="status" aria-live="polite" aria-atomic="true">
        {t('cart.itemCount', { count: totalItems, suffix: totalItems === 1 ? '' : 's' })}. {t('common.total')}: {formatCurrency(finalPrice)}
      </p>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Item list */}
        <section className="flex-1" aria-label={t('cart.cartProductsLabel')}>
          <ul className="flex flex-col gap-4" role="list">
            {cart.map((item) => (
              <li
                key={item.id}
                className="bg-white rounded-2xl shadow p-4 flex items-center gap-4"
              >
                <img
                  src={item.image}
                  alt={item.name}
                  className="w-20 h-20 object-cover rounded-xl shrink-0"
                  loading="lazy"
                  decoding="async"
                />
                <div className="flex-1 min-w-0">
                  <h2 className="font-semibold text-gray-800 truncate">{translateProductText(item.name)}</h2>
                  <p className="text-sm text-gray-500">{formatCurrency(item.price)} × {item.quantity}</p>
                  <p className="text-indigo-600 font-bold">{formatCurrency(item.price * item.quantity)}</p>
                </div>
                {/* Quantity controls */}
                <div className="flex items-center gap-2" role="group" aria-label={t('cart.quantityOf', { name: translateProductText(item.name) })}>
                  <button
                    type="button"
                    onClick={() => handleQuantity(item.id, item.quantity - 1)}
                    className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold transition focus-visible:outline-2 focus-visible:outline-indigo-600"
                    aria-label={t('cart.reduceQuantity', { name: translateProductText(item.name) })}
                  >
                    −
                  </button>
                  <span className="w-6 text-center font-medium" aria-live="polite">{item.quantity}</span>
                  <button
                    type="button"
                    onClick={() => handleQuantity(item.id, item.quantity + 1)}
                    // Disabled when the cap is reached to prevent silent no-ops that confuse users.
                    disabled={item.quantity >= MAX_ITEM_QUANTITY}
                    className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold transition focus-visible:outline-2 focus-visible:outline-indigo-600 disabled:cursor-not-allowed disabled:opacity-50"
                    aria-label={t('cart.increaseQuantity', { name: translateProductText(item.name) })}
                  >
                    +
                  </button>
                </div>
                <button
                  type="button"
                  onClick={() => handleRemove(item.id)}
                  ref={(node) => {
                    if (node) {
                      removeButtonRefs.current.set(item.id, node);
                    } else {
                      removeButtonRefs.current.delete(item.id);
                    }
                  }}
                  className="text-red-400 hover:text-red-600 transition focus-visible:outline-2 focus-visible:outline-red-400 rounded p-1"
                  aria-label={t('cart.removeFromCart', { name: translateProductText(item.name) })}
                >
                  🗑️
                </button>
                <button
                  type="button"
                  onClick={() => {
                    toggleFavorite(item);
                    dispatch({ type: 'REMOVE_ITEM', payload: { id: item.id } });
                    showToast(t('cart.savedToFavorites', { name: translateProductText(item.name) }), 'info');
                  }}
                  className={`rounded-lg border px-2 py-1 text-xs font-medium transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600 ${
                    isFavorite(item.id)
                      ? 'border-rose-300 bg-rose-50 text-rose-600 hover:bg-rose-100'
                      : 'border-gray-300 bg-white text-gray-600 hover:bg-gray-50'
                  }`}
                  aria-label={t('cart.saveForLaterLabel', { name: translateProductText(item.name) })}
                  title={t('cart.saveForLaterTitle')}
                >
                  {isFavorite(item.id) ? t('cart.saved') : t('cart.saveForLater')}
                </button>
              </li>
            ))}
          </ul>
        </section>

        {/* Order summary */}
        <aside className="lg:w-72" aria-label={t('cart.summary')}>
          <div className="bg-white rounded-2xl shadow p-6 sticky top-24">
            <h2 className="font-bold text-gray-800 text-lg mb-4">{t('cart.summary')}</h2>

            {/* Coupon input */}
            <form onSubmit={handleApplyCoupon} className="mb-4" aria-label={t('cart.applyCouponLabel')}>
              <label htmlFor="coupon-input" className="block text-sm font-medium text-gray-700 mb-1">
                {t('cart.discountCoupon')}
              </label>
              <div className="flex gap-2">
                <input
                  ref={couponInputRef}
                  id="coupon-input"
                  type="text"
                  value={couponInput}
                  onChange={(e) => {
                    setCouponInput(e.target.value.toUpperCase());
                    if (couponError) setCouponError('');
                  }}
                  placeholder={t('cart.couponPlaceholder')}
                  title={t('cart.shortcutSlash')}
                  autoComplete="off"
                  disabled={!!coupon}
                  aria-describedby={couponError ? 'coupon-error' : undefined}
                  className="flex-1 min-w-0 rounded-lg border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:bg-gray-50 disabled:text-gray-400 uppercase"
                />
                {coupon ? (
                  <button
                    type="button"
                    onClick={removeCoupon}
                    className="rounded-lg border border-red-300 px-3 py-2 text-sm font-medium text-red-600 transition hover:bg-red-50 focus-visible:outline-2 focus-visible:outline-red-400"
                    aria-label={t('cart.removeCoupon')}
                  >
                    {t('common.remove')}
                  </button>
                ) : (
                  <button
                    type="submit"
                    className="rounded-lg bg-indigo-600 px-3 py-2 text-sm font-medium text-white transition hover:bg-indigo-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
                  >
                    {t('common.apply')}
                  </button>
                )}
              </div>
              {couponError && (
                <p id="coupon-error" className="mt-1 text-xs text-red-500" role="alert">{couponError}</p>
              )}
              {coupon && (
                <div className="mt-1 rounded-md border border-green-200 bg-green-50 px-2 py-2 text-xs text-green-700">
                  <p className="font-medium">✓ {coupon.label}</p>
                  {couponExpiryInfo.expiresOn && (
                    <p>{t('cart.couponExpiresOn')}: {formatDateTime(couponExpiryInfo.expiresOn, { dateStyle: 'medium' })}</p>
                  )}
                  {couponExpiryInfo.isExpiringSoon && (
                    <p className="text-amber-700">
                      {t(
                        couponExpiryInfo.isExpiringToday
                          ? 'cart.couponExpiringSoonToday'
                          : couponExpiryInfo.isExpiringTomorrow
                          ? 'cart.couponExpiringSoonOne'
                          : 'cart.couponExpiringSoonMany',
                        { days: couponExpiryInfo.daysRemaining }
                      )}
                    </p>
                  )}
                </div>
              )}
              {!coupon && (
                <div className="mt-2 flex flex-wrap gap-2" role="group" aria-label={t('cart.suggestedCoupons')}>
                  {couponSuggestions.map((suggestedCoupon) => (
                    <button
                      key={suggestedCoupon.code}
                      type="button"
                      onClick={() => handleApplySuggestedCoupon(suggestedCoupon.code)}
                      className="rounded-full border border-gray-300 bg-white px-2.5 py-1 text-xs font-medium text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
                    >
                      {suggestedCoupon.code}
                    </button>
                  ))}
                </div>
              )}
            </form>

            <dl className="flex flex-col gap-2 text-sm text-gray-600 mb-4">
              <div className="flex justify-between">
                <dt>{t('cart.subtotalItems', { count: totalItems })}</dt>
                <dd className="font-medium">{formatCurrency(totalPrice)}</dd>
              </div>
              {discountAmount > 0 && (
                <div className="flex justify-between">
                  <dt className="text-green-700">{t('common.discount')} ({coupon.code})</dt>
                  <dd className="font-medium text-green-700">−{formatCurrency(discountAmount)}</dd>
                </div>
              )}
              <div className="flex justify-between">
                <dt>{t('common.shipping')}</dt>
                <dd className="text-green-600 font-medium">{t('common.free')}</dd>
              </div>
            </dl>
            <div className="border-t pt-4 flex justify-between font-bold text-gray-900 text-base mb-6">
              <span>{t('common.total')}</span>
              <span>{formatCurrency(finalPrice)}</span>
            </div>
            <button
              type="button"
              onClick={() => setIsConfirmClearOpen(true)}
              className="mb-3 block w-full rounded-xl border border-gray-300 bg-white px-4 py-2.5 text-sm font-semibold text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
            >
              {t('cart.clearCart')}
            </button>
            <Link
              to="/checkout"
              title={t('cart.shortcutCheckout')}
              className="block w-full text-center bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white font-semibold px-4 py-3 rounded-xl transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
            >
              {t('cart.proceedCheckout')}
            </Link>
          </div>
        </aside>
      </div>

      <ConfirmDialog
        open={isConfirmClearOpen}
        title={t('cart.clearCartTitle')}
        message={t('cart.clearCartMessage')}
        onCancel={() => setIsConfirmClearOpen(false)}
        onConfirm={handleClearCart}
        destructive
      />
    </main>
  );
}
